const t=JSON.parse('{"key":"v-3a00749b","path":"/articles/track_record.html","title":"运动轨迹记录软件横评","lang":"zh-CN","frontmatter":{"date":"2022-07-10T00:00:00.000Z","icon":"line","category":["推荐","评价"],"tag":["移动端","横评"],"description":"运动轨迹记录软件横评 我希望找到一款能够记录运动轨迹的软件，在满足需求前提下越小越好。需求：在地图上绘制运动轨迹，定位精确，最好显示方向（由指南针得到）。 评测结果挺让我失望的，有一大批软件连定位精确都无法做到，而且都不约而同地定位到我西北方向数百米。我只能猜想这些软件用了错误的地图，或者久远以前的地图。（我甚至考虑了大陆漂移）因此以下将分为两部分横评。 （后来的测试印证了我的观点：同一软件中使用Google-&gt;标准，地形和卫星地图出现定位偏移，使用OpenStreetMap-&gt;标准地图则未出现偏移。）","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/articles/track_record.html"}],["meta",{"property":"og:site_name","content":"绝对值_x的博客"}],["meta",{"property":"og:title","content":"运动轨迹记录软件横评"}],["meta",{"property":"og:description","content":"运动轨迹记录软件横评 我希望找到一款能够记录运动轨迹的软件，在满足需求前提下越小越好。需求：在地图上绘制运动轨迹，定位精确，最好显示方向（由指南针得到）。 评测结果挺让我失望的，有一大批软件连定位精确都无法做到，而且都不约而同地定位到我西北方向数百米。我只能猜想这些软件用了错误的地图，或者久远以前的地图。（我甚至考虑了大陆漂移）因此以下将分为两部分横评。 （后来的测试印证了我的观点：同一软件中使用Google-&gt;标准，地形和卫星地图出现定位偏移，使用OpenStreetMap-&gt;标准地图则未出现偏移。）"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-07-29T16:46:43.000Z"}],["meta",{"property":"article:tag","content":"移动端"}],["meta",{"property":"article:tag","content":"横评"}],["meta",{"property":"article:published_time","content":"2022-07-10T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-07-29T16:46:43.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"运动轨迹记录软件横评\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2022-07-10T00:00:00.000Z\\",\\"dateModified\\":\\"2023-07-29T16:46:43.000Z\\",\\"author\\":[]}"]]},"headers":[],"git":{"createdTime":1689173144000,"updatedTime":1690649203000,"contributors":[{"name":"lxl66566","email":"18259734087@163.com","commits":3}]},"readingTime":{"minutes":1.67,"words":502},"filePathRelative":"articles/track_record.md","localizedDate":"2022年7月10日","excerpt":"<h1> 运动轨迹记录软件横评</h1>\\n<p>我希望找到一款能够记录运动轨迹的软件，在满足需求前提下越小越好。需求：在地图上绘制运动轨迹，定位精确，最好显示方向（由指南针得到）。</p>\\n<p>评测结果挺让我失望的，有一大批软件连定位精确都无法做到，而且都不约而同地定位到我西北方向数百米。我只能猜想这些软件用了错误的地图，或者久远以前的地图。<span class=\\"heimu\\" title=\\"你知道的太多了\\">（我甚至考虑了大陆漂移）</span>因此以下将分为两部分横评。</p>\\n<p>（后来的测试印证了我的观点：同一软件中使用<code>Google-&gt;标准，地形和卫星地图</code>出现定位偏移，使用<code>OpenStreetMap-&gt;标准地图</code>则未出现偏移。）</p>","autoDesc":true}');export{t as data};
